/*@ Extern Coq (climb_stairs_z: Z -> Z) */
/*@ Import Coq Require Import climb_stairs */

int climbStairs(int n)
/*@ Require
      0 <= n && n <= 45 && emp
    Ensure
      __return == climb_stairs_z(n@pre) && emp
*/
{
    if (n <= 1) {
        return 1;
    }

    int prev2 = 1;
    int prev1 = 1;
    int cur = 0;

    for (int i = 2; i <= n; i++) {
        cur = prev1 + prev2;
        prev2 = prev1;
        prev1 = cur;
    }

    return cur;
}
Require Import ZArith.

Open Scope Z_scope.

Fixpoint climb_stairs_nat (n : nat) : Z :=
  match n with
  | O => 1
  | S O => 1
  | S (S k) => climb_stairs_nat (S k) + climb_stairs_nat k
  end.

Definition climb_stairs_z (n : Z) : Z :=
  climb_stairs_nat (Z.to_nat n).

